definition.script:
pipeline {
  agent any

  options {
    timestamps()
    timeout(time: 30, unit: 'MINUTES')
    buildDiscarder(logRotator(numToKeepStr: '20'))
  }

  environment {
    CI = 'true'
    TEST_ENV = 'production'
  }

  stages {
    stage('Install Dependencies') {
      steps {
        dir('C:\\Swagify\\Swagify_Automation') {
          bat 'npm ci'
          bat 'npx.cmd playwright install chromium'
        }
      }
    }

    stage('Run Tests') {
      steps {
        dir('C:\\Swagify\\Swagify_Automation') {
          script {
            if (params.TEST_SUITE == 'checkout') {
              bat 'npm run test:checkout'
            } else if (params.TEST_SUITE == 'full') {
              bat 'npm test'
            } else {
              bat 'npm run test:ci'
            }
          }
        }
      }
    }
  }

  post {
    always {
      dir('C:\\Swagify\\Swagify_Automation') {
        bat 'npm run dashboard'
        junit allowEmptyResults: true, testResults: 'reports/junit/results.xml'
        archiveArtifacts allowEmptyArchive: true, artifacts: 'playwright-report/**,reports/**,test-results/**', fingerprint: true
      }
    }
  }
}
